-- دفعة رابعة — أسئلة إضافية موجَّهة تحديدًا لإقناع غير المسلمين
-- بأسلوب عقلاني هادئ (لا ضغط عاطفي، كما يمنع التكليف الأصلي صراحة)،
-- على منهج أهل السنة والجماعة وفهم السلف الصالح للأدلة، بلا شذوذ عن
-- الفهم المعتبر. يرفع إجمالي الأسئلة من 35 إلى 45.
-- status='draft'، is_approved=false إلزاميًا.
INSERT INTO dawah_questions (category_id, slug, title, short_answer, detailed_answer, evidences, glossary_terms, sources, keywords, status, is_approved) VALUES

((SELECT id FROM dawah_categories WHERE slug='entering-islam'), 'what-distinguishes-islam',
'ما الذي يميّز الإسلام حقًا عن باقي الأديان؟',
'اجتماع أربع خصائص نادرًا ما تجتمع معًا في دين واحد: نص مقدَّس محفوظ بلا تحريف موثَّق تاريخيًا، توحيد خالص بلا وسيط بين العبد وربه، شريعة شاملة تنظّم العبادة والأخلاق والحياة معًا لا العبادة وحدها، وخاتمية واضحة تُنهي الحاجة لانتظار وحي جديد.',
'حين يُقارَن الإسلام بغيره من الأديان بموضوعية، تبرز أربع خصائص مجتمعة نادرًا ما توجد معًا في دين واحد: أولًا، حفظ النص المقدَّس (القرآن) بسند متواتر موثَّق تاريخيًا لا يعتمد على مخطوطات متأخرة مختلَف على نسبتها كما هو حال نصوص أخرى قديمة. ثانيًا، توحيد خالص مباشر بلا وسيط كهنوتي أو أقنوم بين العبد وربه، فكل إنسان يدعو الله مباشرة. ثالثًا، شمولية الشريعة: لا فصل بين "الديني" و"الدنيوي"، فالعبادة والأخلاق والمعاملات المالية والأسرية كلها منظومة واحدة متكاملة. رابعًا، خاتمية الرسالة: لا حاجة لانتظار نبي جديد أو تفسير مركزي متجدد، فالرسالة اكتملت ووُثّقت. هذا لا يعني تسفيه الأديان الأخرى أو مقارنتها استعلائيًا، بل عرضًا موضوعيًا لما يراه المسلم نقاط قوة فريدة يستحق أي باحث صادق عن الحقيقة النظر فيها بعقل مفتوح.',
'[{"type":"quran","ref":"المائدة: ٣","text":"الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي وَرَضِيتُ لَكُمُ الْإِسْلَامَ دِينًا"}]'::jsonb,
'[]'::jsonb, '[]'::jsonb,
ARRAY['تميّز الإسلام','مقارنة الأديان'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='purpose-of-life'), 'can-i-be-happy-without-religion',
'ألا يمكنني أن أعيش حياة سعيدة وأخلاقية دون أي دين؟',
'يمكن لغير المتدين أن يعيش حياة منضبطة أخلاقيًا وسعيدة ظاهريًا، لكن التصور الإسلامي يرى أن السعادة الكاملة والمعنى العميق يحتاجان مرجعية ثابتة للغاية والقيمة تتجاوز الذات الفردية المحدودة، لا مجرد التزام أخلاقي بلا أساس غائي واضح.',
'من الأمانة الإقرار بأن كثيرًا من غير المتدينين يعيشون فعلًا حياة منضبطة أخلاقيًا وسعيدة ظاهريًا، وهذا لا يُنكِره الإسلام. لكن السؤال الأعمق الذي يطرحه التصور الإسلامي: من أين تستمد هذه الأخلاق والسعادة معناها النهائي واستقرارها إن لم يكن هناك غاية كونية تتجاوز الفرد؟ بلا مرجعية ثابتة، تصبح الأخلاق نفسها مسألة تفضيل شخصي أو اجتماعي قابل للتغير الجذري بتغير الظرف أو الرأي العام، ويصبح "المعنى" مسألة اختراع شخصي مؤقت ينتهي بانتهاء الفرد نفسه بلا امتداد أبدي. الإسلام يقدّم إطارًا يمنح السعادة والأخلاق أساسًا ثابتًا يتجاوز تقلّبات الفرد والمجتمع: غاية واضحة (عبادة الله)، ومرجعية أخلاقية ثابتة (الوحي)، وامتدادًا أبديًا للمعنى (الآخرة) يتجاوز الأربعين أو الثمانين عامًا من العمر الدنيوي. هذا لا يُلزِم أحدًا بالإيمان قسرًا، لكنه يستحق تأملًا صادقًا: هل السعادة بلا هذا الأفق الأوسع مستقرة حقًا، أم أنها هشة أمام أزمات الحياة الكبرى كالمرض والموت وفقد الأحبة؟',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['السعادة بلا دين','الأخلاق العلمانية','المعنى'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='quran'), 'quran-proof-divine-origin',
'ما الدليل على أن القرآن من عند الله لا من تأليف محمد ﷺ؟',
'عدة أدلة مجتمعة: إعجاز بلاغي ولغوي فريد شهد به حتى ألد أعداء النبي ﷺ من العرب الفصحاء، أُمّية النبي ﷺ (لم يُعرَف عنه قراءة ولا كتابة)، وثبات النص دون تناقض داخلي رغم نزوله مفرَّقًا على ٢٣ سنة وظروف متقلبة جدًا.',
'يستدل علماء الإسلام على المصدر الإلهي للقرآن بعدة أدلة متكاملة: أولًا، الإعجاز البلاغي: نزل القرآن في بيئة عربية بلغت ذروة الفصاحة الشعرية، وتحدّى القرآن صراحة أبلغ فصحاء العرب أن يأتوا بمثله أو حتى بسورة من مثله، فعجزوا رغم عداوتهم الشديدة للنبي ﷺ ورغم أن الطعن الأدبي كان أسهل سلاح متاح لهم لو استطاعوا. ثانيًا، أمّية النبي ﷺ: لم يُعرَف عنه قبل النبوة تعلّم القراءة أو الكتابة أو ارتياد مجالس علم أو شعر منظّم، وهذا يجعل تأليف نص بهذا المستوى اللغوي والمعرفي (يتضمن قصصًا تاريخية دقيقة وتشريعات متكاملة) أمرًا بعيدًا جدًا عن قدرة شخص بهذه الخلفية دون مصدر خارج ذاته. ثالثًا، الاتساق الداخلي: نزل القرآن مفرَّقًا على مدى ٢٣ سنة في ظروف نفسية واجتماعية وسياسية شديدة التقلّب (اضطهاد، هجرة، حروب، انتصارات)، ومع ذلك لا يحمل النص تناقضًا جوهريًا يعكس هذا التقلّب النفسي المتوقَّع من مؤلف بشري يمر بتجارب متضاربة كهذه على مدى عقدين كاملين.',
'[{"type":"quran","ref":"البقرة: ٢٣","text":"وَإِن كُنتُمْ فِي رَيْبٍ مِّمَّا نَزَّلْنَا عَلَىٰ عَبْدِنَا فَأْتُوا بِسُورَةٍ مِّن مِّثْلِهِ"}, {"type":"quran","ref":"العنكبوت: ٤٨","text":"وَمَا كُنتَ تَتْلُو مِن قَبْلِهِ مِن كِتَابٍ وَلَا تَخُطُّهُ بِيَمِينِكَ"}]'::jsonb,
'[]'::jsonb, '[]'::jsonb,
ARRAY['إعجاز القرآن','مصدر القرآن','التحدي'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='prophethood'), 'muhammad-truthfulness-evidence',
'كيف أعرف أن محمدًا ﷺ لم يكن كاذبًا أو واهمًا؟',
'شهادة قومه أنفسهم (حتى المعادين له) بصدقه وأمانته قبل النبوة، وغياب أي دافع دنيوي واضح يبرر الكذب (تحمّل الأذى والفقر بدل المكاسب المعروضة عليه)، واستمرار ثباته على الدعوة رغم أقسى أنواع الاضطهاد لعقدين كاملين.',
'يقدّم الباحثون في السيرة النبوية عدة قرائن عقلية على استبعاد فرضيتي الكذب المتعمَّد أو الوهم النفسي: أولًا، شهد له قومه أنفسهم، بمن فيهم من عادوه لاحقًا بعد النبوة أشد العداء، بالصدق والأمانة طوال أربعين سنة قبل البعثة، حتى لُقِّب بـ"الصادق الأمين" — وهذا يجعل افتراض تحوّله فجأة لكاذب كبير يفتري على الله أمرًا يحتاج تفسيرًا مقنعًا لم يقدّمه خصومه أنفسهم في حينه. ثانيًا، غياب الدافع الدنيوي: عُرِض عليه من قومه المال والملك والزواج مقابل ترك دعوته فرفض، واختار بدل ذلك سنوات من الأذى والمقاطعة الاجتماعية والفقر، وهذا يناقض المنطق المعتاد لمن يكذب طلبًا للمكاسب الدنيوية. ثالثًا، ثباته على الدعوة عقدين كاملين رغم أقسى أنواع الاضطهاد (تعذيب أصحابه، محاولات اغتياله، مقاطعة اقتصادية جماعية) يصعب تفسيره بوهم نفسي عابر أو كذب مصلحي مؤقت، بل يتسق أكثر مع يقين داخلي عميق بصدق ما يدعو إليه.',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['صدق النبي','السيرة النبوية','الأمانة'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='worship'), 'practical-benefits-of-worship',
'ما الفائدة العملية الحقيقية للصلاة والعبادة في حياتي؟',
'انضباط يومي منتظم يقوّي الإرادة، وتواصل مباشر مع الله يخفف القلق والوحدة النفسية، وتوقفات متكررة للمراجعة الذاتية تمنع الانجراف الأخلاقي، وإحساس مستمر بالمعنى والمراقبة الذاتية حتى في الخلوة.',
'بعيدًا عن البُعد الأخروي، تحمل العبادات في الإسلام فوائد نفسية واجتماعية عملية ملموسة حتى في هذه الحياة: الصلوات الخمس المنتظمة تخلق إيقاعًا يوميًا ثابتًا يقوّي الانضباط الذاتي والإرادة، وتمنح خمس فرص يومية للتوقف والمراجعة النفسية وسط ضغوط الحياة، وهذا مثبَت نفسيًا كعامل مخفِّف للقلق والتوتر في ممارسات تأملية مشابهة. الدعاء المباشر لله يمنح إحساسًا عميقًا بأنك لست وحدك في مواجهة صعوبات الحياة، ويخفف الشعور بالوحدة الوجودية. الصيام يُدرِّب على ضبط النفس وتقدير النعم بعد حرمان مؤقت منها. الزكاة تربط الفرد بمجتمعه وتخفف تركيزه المفرط على المادة. مراقبة الله المستمرة (الإحسان: "أن تعبد الله كأنك تراه") تخلق ضميرًا أخلاقيًا داخليًا ثابتًا يعمل حتى في الخلوة التامة بلا حاجة لرقابة خارجية، وهذا أثر عملي مباشر على الاستقامة الأخلاقية اليومية بعيدًا عن أي بُعد أخروي مجرد.',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['فوائد العبادة','الصحة النفسية','الانضباط'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='jihad'), 'is-islam-really-peaceful',
'هل الإسلام دين سلام حقًا كما يدّعي أتباعه؟',
'الأصل في العلاقة مع الآخرين في الإسلام السلم لا الحرب، والقتال استثناء مقيَّد بشروط دفاعية صارمة لا قاعدة عامة — لكن "السلام" في الإسلام ليس غياب كل قوة أو دفاع، بل عدالة منضبطة تمنع الاعتداء وترد الظلم.',
'كلمة "الإسلام" نفسها من جذر "السلم"، وتحية المسلمين اليومية المتكررة "السلام عليكم" تختصر توجّهًا مركزيًا في الدين. الأصل الفقهي في العلاقة مع غير المسلمين المسالمين هو البرّ والعدل لا العداء، كما وضّحنا في سؤال منفصل عن معاملة غير المسلمين. لكن من المهم توضيح فهم دقيق لمعنى "السلام" هنا: ليس المقصود سلامًا سلبيًا مطلقًا يرفض أي دفاع عن النفس أو رد أي عدوان مهما بلغ، بل عدالة منضبطة تسمح بالدفاع المشروع عند وقوع اعتداء فعلي، وهذا معيار عقلاني تتبناه كل الأنظمة القانونية العادلة في العالم (حق الدفاع الشرعي عن النفس). القتال في الإسلام، حين يُشرَع، محكوم بشروط صارمة جدًا (كما فُصِّل في مادة مستقلة عن سياق آيات القتال): لا يجوز إلا بإذن ولي أمر شرعي، وضمن سياق دفاعي أو رد عدوان واضح غالبًا، مع ضوابط أخلاقية صارمة حتى في الحرب (تحريم قتل غير المقاتلين، حفظ العهود). هذا يجعل "السلام الإسلامي" أقرب لمفهوم "العدل المسلَّح" لا "اللاعنف المطلق"، وهو تمييز مهم لفهم الموقف الإسلامي بدقة.',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['السلام في الإسلام','الدفاع عن النفس'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='purpose-of-life'), 'spiritual-emptiness-despite-success',
'لماذا أشعر بفراغ روحي رغم نجاحي المادي؟',
'الإنجاز المادي يُشبع احتياجات مؤقتة لكنه لا يملأ حاجة الإنسان الفطرية العميقة لغاية تتجاوز الذات وعلاقة حقيقية بخالقه — هذا الفراغ نفسه، في التصور الإسلامي، دليل فطري على وجود هذه الحاجة الروحية غير المُشبَعة.',
'هذا الشعور بالفراغ رغم النجاح الظاهري تجربة إنسانية شائعة جدًا وموثَّقة نفسيًا واجتماعيًا، يعبّر عنها كثير ممن حققوا نجاحًا ماديًا كبيرًا دون أن يجدوا السكينة المتوقَّعة. يفسّر التصور الإسلامي هذا بأن الإنسان مفطور على حاجة روحية عميقة لعلاقة مباشرة بخالقه ومعنى يتجاوز إنجازاته المادية المحدودة زمنيًا، وأن هذه الحاجة لا يمكن أن تُشبَع بمراكمة المال أو المنصب أو المتعة وحدها، تمامًا كما لا يُشبِع الطعام حاجة الإنسان للحب أو الانتماء. القرآن يصف هذا بدقة: "أَلَا بِذِكْرِ اللَّهِ تَطْمَئِنُّ الْقُلُوبُ" — الطمأنينة الحقيقية مرتبطة بذكر الله والاتصال به، لا بتراكم الإنجاز المادي المجرد. هذا الفراغ الذي تشعر به ليس عيبًا فيك، بل إشارة فطرية طبيعية لحاجة حقيقية لم تُشبَع بعد، تستحق أن تُستكشَف بجدية بدل تجاهلها أو محاولة كتمها بمزيد من الإنجاز الذي أثبتت التجربة أنه لا يكفي وحده.',
'[{"type":"quran","ref":"الرعد: ٢٨","text":"أَلَا بِذِكْرِ اللَّهِ تَطْمَئِنُّ الْقُلُوبُ"}]'::jsonb,
'[]'::jsonb, '[]'::jsonb,
ARRAY['الفراغ الروحي','الطمأنينة','النجاح المادي'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='god-existence'), 'fitrah-natural-inclination-to-believe',
'ما هي الفطرة، ولماذا يميل الإنسان طبيعيًا للإيمان بخالق؟',
'الفطرة هي الاستعداد الغريزي الذي خُلق عليه كل إنسان، ويتضمن ميلًا طبيعيًا لمعرفة الله والانجذاب للتوحيد قبل أي تعليم أو تنشئة خارجية — وهذا يفسر لماذا يبرز الشعور الديني أو البحث عن معنى متعالٍ لدى أغلب الثقافات الإنسانية عبر التاريخ رغم اختلاف تفاصيلها.',
'يعلّم الإسلام أن كل إنسان يولد على "الفطرة"، وهي استعداد غريزي فطري يتضمن ميلًا طبيعيًا لمعرفة الخالق والانجذاب نحو التوحيد، قبل أن يتأثر بتنشئة اجتماعية أو ثقافية معينة قد تُبعِده عن هذا الميل الفطري أو تُشوِّهه. هذا يفسّر ظاهرة ملاحظة اجتماعية وتاريخية واسعة: بروز شكل من أشكال الشعور الديني أو البحث عن معنى متعالٍ لدى الغالبية العظمى من الثقافات الإنسانية عبر التاريخ، رغم شدة اختلاف تفاصيل معتقداتها، وكأن هناك ميلًا إنسانيًا مشتركًا أعمق من مجرد اختراع ثقافي عشوائي منفصل الجذور. هذا لا يعني أن كل إنسان يشعر بهذا الميل بنفس القوة أو الوضوح دومًا (فقد تُضعِفه عوامل تنشئة أو تجارب حياتية معينة)، لكنه يفسّر لماذا يجد كثير ممن يبتعدون عن الإيمان لفترة أنفسهم يعودون للبحث عن معنى متعالٍ في مرحلة لاحقة من حياتهم، وكأنهم يستجيبون لنداء داخلي فطري لم يُطفَأ كليًا.',
'[{"type":"hadith","ref":"متفق عليه، من حديث أبي هريرة رضي الله عنه","grading":"صحيح متفق عليه","text":"كُلُّ مَوْلُودٍ يُولَدُ عَلَى الْفِطْرَةِ، فَأَبَوَاهُ يُهَوِّدَانِهِ أَوْ يُنَصِّرَانِهِ أَوْ يُمَجِّسَانِهِ"}]'::jsonb,
'[{"term":"الفطرة","definition":"الاستعداد الغريزي الفطري الذي خُلق عليه كل إنسان، ويتضمن ميلًا طبيعيًا لمعرفة الله والتوحيد."}]'::jsonb,
'[]'::jsonb,
ARRAY['الفطرة','الميل الفطري للإيمان'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='islamic-history'), 'sunnah-and-salaf-methodology',
'ما معنى الاستناد إلى "أهل السنة والجماعة" و"السلف الصالح" في فهم الإسلام؟',
'أهل السنة والجماعة هم عموم المسلمين الملتزمين بفهم الصحابة والتابعين (السلف الصالح) للقرآن والسنة، بمنهج وسطي متوازن بين الجمود الحرفي والتأويل المنفلت — وهذا المنهج هو المرجعية المعتمَدة في عرض محتوى هذه المنصة تحديدًا.',
'حين تقرأ محتوى هذه المنصة، من المهم أن تعرف المنهج العلمي الذي تعتمده: "أهل السنة والجماعة" مصطلح يشير إلى غالبية المسلمين عبر التاريخ الملتزمين بفهم القرآن والسنة النبوية كما فهمه ونقله جيل الصحابة رضي الله عنهم (من عاصروا النبي ﷺ مباشرة) ومن تبعهم بإحسان من التابعين وتابعيهم، ويُعرَف هذا الجيل المبكر بـ"السلف الصالح". لماذا يُعتمَد هذا المنهج تحديدًا؟ لأن هذا الجيل الأقرب زمنيًا ولغويًا وثقافيًا للنبي ﷺ ولنزول الوحي هو الأقدر على فهم مقاصد النصوص بدقة، بمنهج وسطي متوازن يتجنب طرفين متطرفين: الجمود الحرفي المتجاهل لمقاصد النصوص وحكمها من جهة، والتأويل المنفلت الذي يُخضِع النص لأهواء العصر المتغيرة من جهة أخرى. هذا لا يعني إنكار وجود اجتهادات فقهية متعددة معتبرة ضمن هذا الإطار العام (كالمذاهب الفقهية الأربعة المعروفة)، بل يعني الالتزام بإطار منهجي عام ثابت في فهم النصوص الأساسية للعقيدة، لا الانفراد بتفسيرات شاذة عن هذا الفهم الجماعي المستقر عبر القرون.',
'[]'::jsonb,
'[{"term":"السلف الصالح","definition":"الصحابة رضي الله عنهم ومن تبعهم بإحسان من التابعين وتابعيهم — الأجيال الثلاثة الأولى المشهود لها بالخيرية."}, {"term":"أهل السنة والجماعة","definition":"غالبية المسلمين الملتزمين بفهم السلف الصالح للقرآن والسنة، ضمن إطار وسطي متوازن يستوعب تعدد المذاهب الفقهية المعتبرة."}]'::jsonb,
'[]'::jsonb,
ARRAY['أهل السنة والجماعة','السلف الصالح','المنهج العلمي'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='evil-suffering'), 'death-and-eternity-in-islam',
'كيف يفسّر الإسلام معنى الموت، وهل هناك حياة بعده؟',
'الموت في التصور الإسلامي ليس نهاية العدم، بل انتقال من حياة دنيا مؤقتة إلى حياة برزخية ثم حياة أخروية أبدية، يُحاسَب فيها كل إنسان على عمله بعدل تام — وهذا يمنح الحياة الدنيا معنى ممتدًا لا ينتهي بانتهاء الجسد.',
'يقدّم الإسلام تصورًا متكاملًا لما بعد الموت يمنح الحياة معنى يتجاوز حدودها الزمنية القصيرة: الموت ليس عدمًا نهائيًا، بل انتقال إلى مرحلة تُسمى "البرزخ" (فترة انتظار بين الموت والبعث)، ثم بعث جميع الخلق يوم القيامة للحساب، حيث يُحاسَب كل إنسان بعدل تام على كل عمل صغير أو كبير فعله في حياته الدنيا، ثم مصير أبدي إما في الجنة (نعيم دائم) أو النار (عاقبة الظلم والكفر المُصِرّ عليه)، حسب عدل الله ورحمته معًا. هذا التصور يمنح الحياة الدنيا معنى أعمق بكثير من مجرد "الاستمتاع قبل الفناء": كل عمل خير أو شر له امتداد أبدي فعلي، وهذا يمنح دافعًا أخلاقيًا حقيقيًا للاستقامة حتى في الخلوة التامة حيث لا رقيب بشري، ويمنح المتألم في الدنيا (كمن يعاني ظلمًا أو مرضًا) رجاءً حقيقيًا بعدالة نهائية لا تفوت الله سبحانه مهما طال الزمن الدنيوي.',
'[{"type":"quran","ref":"الزلزلة: ٧-٨","text":"فَمَن يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ * وَمَن يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُ"}]'::jsonb,
'[{"term":"البرزخ","definition":"المرحلة الزمنية بين موت الإنسان وبعثه يوم القيامة."}]'::jsonb,
'[]'::jsonb,
